// AddNew.jsx — ANDROID FORMAT (Single Box with 3 Cards)
// UI not changed, only layout improved for mobile/android use.

import React from "react";
import { useNavigate } from "react-router-dom";
import "./AddNew.css";

export default function AddNew({ employee }) {
  const navigate = useNavigate();

  const green = "#0f9d58";
  const lightGreen = "#eaf8f0";

  return (
    <div className="addnew-outer">
      {/* === MAIN CENTERED ANDROID CARD === */}
      <div className="addnew-main-card">

        {/* === HEADER WITH BACK ARROW === */}
        <div className="addnew-header-row">
          <button className="addnew-back-btn" onClick={() => navigate("/home")}>
            ←
          </button>

          <h2 className="addnew-title">Add New</h2>
        </div>

        {/* EMPLOYEE DETAILS */}
        <p className="addnew-emp-info">
          Employee: {employee?.name} • {employee?.empld}
        </p>

        {/* === INNER BOX HOLDING 3 OPTIONS === */}
        <div className="addnew-options-box">

          {/* ----- TRAVEL EXPENSE ----- */}
          <div
            className="addnew-option-card"
            onClick={() => navigate("/add/travel")}
          >
            <h3>Travel Expense</h3>
            <p>Add travel details & amount</p>
          </div>

          {/* ----- TICKET EXPENSE ----- */}
          <div
            className="addnew-option-card"
            onClick={() => navigate("/add/ticket")}
          >
            <h3>Ticket Expense</h3>
            <p>Add ticket details & amount</p>
          </div>

          {/* ----- UPLOAD BILLS ----- */}
          <div
            className="addnew-option-card"
            onClick={() => navigate("/add/upload-bills")}
          >
            <h3>Upload Bills</h3>
            <p>Upload receipts for reimbursement</p>
          </div>

        </div>
      </div>
    </div>
  );
}
